public class Reverse {
    public static void main(String[] args) {
        String s = "hello";
        System.out.println("Reverse of '" + s + "': " + reverse(s));
    }

    public static String reverse(String s) {
        String result = "";
        for (int i = s.length() - 1; i >= 0; i--) {
            result += s.charAt(i);
        }
        return result;
    }
}

public class Palindrome {
    public static void main(String[] args) {
        System.out.println("'racecar' palindrome? " + isPalindrome("racecar"));
        System.out.println("'hello' palindrome? " + isPalindrome("hello"));
        System.out.println("'Level' palindrome? " + isPalindrome("Level"));
    }

    public static boolean isPalindrome(String s) {
        s = s.toLowerCase();
        int left = 0;
        int right = s.length() - 1;
        while (left < right) {
            if (s.charAt(left) != s.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
}

public class WordCount {
    public static void main(String[] args) {
        String text = "The cat sat on the mat";
        String word = "the";
        int count = countOccurrences(text, word);
        System.out.println("'" + word + "' appears " + count + " times in '" + text + "'");
    }

    public static int countOccurrences(String text, String word) {
        String[] words = text.toLowerCase().split(" ");
        String target = word.toLowerCase();
        int count = 0;
        for (String w : words) {
            if (w.equals(target)) {
                count++;
            }
        }
        return count;
    }
}

public class TitleCase {
    public static void main(String[] args) {
        String s = "hello world from JAVA";
        System.out.println("Title case: " + toTitleCase(s));
    }

    public static String toTitleCase(String s) {
        String[] words = s.split(" ");
        String result = "";
        for (int i = 0; i < words.length; i++) {
            String word = words[i].toLowerCase();
            if (word.length() > 0) {
                String capitalized = word.substring(0, 1).toUpperCase() + word.substring(1);
                result += capitalized;
            }
            if (i < words.length - 1) {
                result += " ";
            }
        }
        return result;
    }
}

public class FirstUnique {
    public static void main(String[] args) {
        System.out.println("First unique in 'swiss': " + firstNonRepeating("swiss"));
        System.out.println("First unique in 'hello': " + firstNonRepeating("hello"));
        System.out.println("First unique in 'aabbcc': " + firstNonRepeating("aabbcc") + " (space if all repeat)");
    }

    public static char firstNonRepeating(String s) {
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            int count = 0;
            for (int j = 0; j < s.length(); j++) {
                if (s.charAt(j) == c) {
                    count++;
                }
            }
            if (count == 1) {
                return c;
            }
        }
        return ' ';
    }
}
